-- بذر مقالات إسلامية عالية الجودة (Premium Islamic Articles)
-- ===============================================

INSERT INTO public.articles (title, content, category, author_id, views_count) VALUES
('أهمية التوحيد في حياة المسلم', 'التوحيد هو أساس هذا الدين، وهو الغاية التي من أجلها خلق الله الجن والإنس... \n\nإن التوحيد ليس مجرد كلمة تقال باللسان، بل هو عقيدة راسخة في القلب تظهر آثارها على الجوارح. فالمسلم الموحد يدرك أن النافع والضار هو الله، وأن الرزق بيده وحده، مما يورثه طمأنينة لا تزلزلها المحن.\n\nإن فضل التوحيد عظيم، فهو أعظم الحسنات، وبه يكفر الله السيئات، وهو السبيل الوحيد لدخول الجنة والنجاة من النار.\n\nفلنحرص على تعلم التوحيد وتعليمه، وتطبيقه في واقعنا بالتوكل والعبادة الخالصة لله.', 'العقيدة والتوحيد', NULL, 150),

('رمضان.. معسكر إيماني للتغيير', 'رمضان ليس مجرد شهر للصيام عن الطعام والشراب، بل هو دورة تربوية متكاملة تهدف إلى تهذيب النفس... \n\nفي هذا الشهر الكريم، يتدرب المسلم على مراقبة الله في السر والعلن، ويقوي إرادته في مواجهة الشهوات. الصيام يعلمنا الصبر، والقيام يعلمنا الخشوع، والصدقة تعلمنا الجود.\n\nإن الهدف الأسمى من الصيام هو تحقيق التقوى، كما قال تعالى: "لعلكم تتقون". فإذا خرج المسلم من رمضان وقد تغير حاله للأفضل، فهذا هو الفلاح.\n\nفلنجعل من رمضان نقطة انطلاق نحو الاستقامة الدائمة، ونحافظ على مكتسباته من تلاوة وقيام وخلق كريم.', 'عبادات وفضائل', NULL, 280),

('أدب المعاملة في الإسلام', 'لقد جاء الإسلام بمنظومة أخلاقية متكاملة تنظم علاقة المسلم بغيره، سواء كان مسلماً أو غير مسلم... \n\nالأخلاق في الإسلام ليست فضيلة ثانوية، بل هي جوهر التدين. سُئل رسول الله صلى الله عليه وسلم عن أكثر ما يدخل الناس الجنة فقال: "تقوى الله وحسن الخلق".\n\nإن الابتسامة في وجه أخيك صدقة، والكلمة الطيبة صدقة، وحسن الجوار إيمان. المسلم هو من سلم الناس من لسانه ويده.\n\nعندما نلتزم بآداب المعاملة، فإننا ندعو لهذا الدين بأفعالنا قبل أقوالنا، وننشر روح المحبة والتآخي في المجتمع.', 'الأخلاق والآداب', NULL, 2010);
